const numPatients = 5;

const diagnoses = [
  'Artrosis severa de rodilla bilateral', 
  'Lumbalgia crónica inespecífica con kinesiofobia', 
  'Síndrome de fragilidad geriátrica y sarcopenia', 
  'Dolor crónico generalizado (sospecha de sensibilización central)', 
  'Fractura de cadera reciente post-quirúrgica'
];

const barthelScores = [
  '20 (Dependencia grave)', 
  '45 (Dependencia moderada)', 
  '60 (Dependencia leve)', 
  '90 (Independiente para ABVD)'
];

const painVAS = ['4/10', '6/10', '8/10', '9/10 (Dolor irruptivo)'];

const comorbidities = [
  'Deterioro cognitivo leve', 
  'Polifarmacia (más de 8 fármacos)', 
  'Aislamiento social y estado anímico bajo', 
  'Hipertensión y riesgo moderado de caídas'
];

const genders = ['Hombre', 'Mujer'];

// Función auxiliar para elegir un elemento aleatorio
const getRandom = (arr) => arr[Math.floor(Math.random() * arr.length)];

let syntheticPatients = [];

for (let i = 0; i < numPatients; i++) {
  // Edad aleatoria entre 18 y 95 años (ambos inclusive)
let age = Math.floor(Math.random() * (95 - 18 + 1)) + 18;

  // ID con formato GER-001, GER-002...
  let patientId = String(i + 1).padStart(3, '0');

  syntheticPatients.push({
    json: {
      patient_id: patientId,
      age: age,
      gender: getRandom(genders),
      main_diagnosis: getRandom(diagnoses),
      barthel_index: getRandom(barthelScores),
      pain_level: getRandom(painVAS),
      comorbid_context: getRandom(comorbidities)
    }
  });
}

return syntheticPatients;;

